import{_ as o,o as t,c as e,ag as n}from"./chunks/framework.sFGfN9OF.js";const h=JSON.parse('{"title":"Spring Boot 自动装配","description":"","frontmatter":{},"headers":[],"relativePath":"spring/boot-autoconfiguration.md","filePath":"spring/boot-autoconfiguration.md","lastUpdated":1776563650000}'),r={name:"spring/boot-autoconfiguration.md"};function i(l,a,p,s,c,d){return t(),e("div",null,[...a[0]||(a[0]=[n('<h1 id="spring-boot-自动装配" tabindex="-1">Spring Boot 自动装配 <a class="header-anchor" href="#spring-boot-自动装配" aria-label="Permalink to &quot;Spring Boot 自动装配&quot;">​</a></h1><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>为什么 Spring Boot 只要引入 starter 并写少量配置，就能自动把大量 Bean 装配好？</p><h2 id="explanation" tabindex="-1">Explanation <a class="header-anchor" href="#explanation" aria-label="Permalink to &quot;Explanation&quot;">​</a></h2><p>Spring Boot 的自动装配能力来自 <code>@SpringBootApplication</code> 中的 <code>@EnableAutoConfiguration</code>。启动时框架会读取自动配置类清单，再基于条件注解判断当前环境是否满足装配条件，例如类路径中是否存在某个依赖、配置文件中是否启用某个特性、容器里是否已经有同类型 Bean。</p><p>这种机制让框架在“约定优于配置”的前提下提供开箱即用体验，同时保留覆盖默认实现的能力。业务方如果需要自定义 Bean，可以通过显式声明 Bean 的方式覆盖默认装配结果。</p><h2 id="key-points" tabindex="-1">Key Points <a class="header-anchor" href="#key-points" aria-label="Permalink to &quot;Key Points&quot;">​</a></h2><ul><li>自动装配的入口是 <code>@EnableAutoConfiguration</code>。</li><li>条件注解决定配置是否真正生效。</li><li>starter 负责依赖聚合，自动配置负责行为注入。</li><li>自定义 Bean 时要关注是否会覆盖默认配置。</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Spring Boot 自动装配的本质，是基于条件判断动态导入配置类。理解它之后，排查 Bean 冲突和自定义 starter 都会更顺手。</p>',10)])])}const m=o(r,[["render",i]]);export{h as __pageData,m as default};
